Scripts.Script:
				// 


    var  enabled = false,
	gdelayShow = 10000,
        gdelayCheck = 200,
		navDest = "",
        LaunchChNum = -1;

        var channelOrig, channelNew;

function init() {
    channelOrig = getProperty("FsDS", "channel");
    if (channelOrig == "9999") {
        invokeAction(null, "Kill");
        return false
    }
    checkChannelW()
}

function loadApp() {
    if (checkChannelW()) {
        invokeAction("","InitialDelay");

    }
}

function checkChannelW() {
//alert("checkChannelW")
    channelNew = getProperty("FsDS", "channel");
    if (channelNew == "9999") {
        invokeAction("", "Kill");
        return false
    }
    if (channelNew != channelOrig) {
        //invokeAction("", "Kill");
        return true
		}

    setTimeout("checkChannelW()", 60000);
    return true
}


   function checkRez() {
    //setProperty("Msg", "visible", "false");
    var w = getProperty("SystemDS", "width")
    alert("width: " + w);
    if (w == "640") {
        setProperty("GenericTrigger", "width", 640);
       //setProperty("Msg", "width", 640);
    }
}

function checkChannel() {

          invokeAction("","RefreshFS");
                        var b = getProperty("FsDS", "channel"),
                            c = LaunchChNum;

                    alert("b -" + b + "c - " + c );
                    if(c == "-1")
                    {
                      alert("lcn set to " + b);
                      LaunchChNum = b;
                    }
                    else if( c != b)
                    {
                      alert("diff channel");
                      invokeAction("", "Kill");
                    }
                    else
                      alert("still on launch channel");
                }

  function handleKey() {

  var a = window.readContext("keyname");
  if(a="select"){
     var b = getProperty("Panel", "visible");

                            if (b == "false") {
                                setProperty("Panel", "visible", "true");
                                invokeAction("", "HideMessage_Delayed")
                            } else {

								goToVOD()
								invokeAction("", "Kill");
                            }
			}
		    else
			{
                 window.writeContext("handled", false);
               if (a != "mute" && a != "volumeup" && a != "volumedown" && a != "play" && a != "pause" && a != "record" && a != "rec" && a != "skipfwd" && a != "skipback" && a != "rwd" && a != "ffwd" && a != "stop") {
                alert("handle key action");
                 invokeAction("", "Kill");
		        }
			}
    }



function checkMsgToggle() {
    alert("checkMesgToggle");
    var gg = '/root/@active';
    var hh = getProperty("HsiaCheckDS", gg);
	alert("hh " + hh);
    if(hh == 'off')
    {
      invokeAction("", "Kill");
    }
	else{

        //chk msg count
        var pp = getProperty("HsiaCheckDS", '//msgs/msg');
        alert("pp " + pp);
        if(pp == null)
        {
          invokeAction("", "Kill");
        }
		else {
		 var gp = "|"+ getProperty("FsDS", "channel") + "|";
     alert("gp" + gp);
    var ga ="//msgs/msg[contains(@chs,'"+gp+"')]";
    alert("ga - " + ga);
    var qq = getProperty("HsiaCheckDS", ga);
    alert("qq - " + qq);
    setProperty("L", "url", getProperty("HsiaCheckDS", '//msgs/msg/@iu'));
	navDest = getProperty("HsiaCheckDS", '//msgs/msg/@nav')
  if (!enabled) {
    enable()
	}
		}
	}

}

function hideMsg()
{
  invokeAction("", "HideMsg");
}

function checkMsgDelayed()
{
    checkChannel();
    invokeAction("", "ShowMsg");
    setTimeout("validateChannel()", gdelayCheck);
    //invokeAction("", "CheckChannel_Delayed");
}

function validateChannel()
{

  checkChannel();
  setTimeout("validateChannel()", gdelayCheck);
  //invokeAction("", "CheckChannel_Delayed");
}

function exit()
{
    alert("killlayer")
    invokeAction("", "killlayer");

}


 function enable() {
                    alert("enable");
                   /* if (debug) {
                     setProperty("DebugLabel", "text", "")
                    }*/
                    var a = getProperty("Panel", "visible");
                        checkChannel()
                        alert("\n checkchannel passed");
                        if (!enabled) {
                            alert("\n setting enabled true");
                            enabled = true;

                            alert("\n set cta image");
                            setProperty("FocusButton", "visible", "true");
                            //setProperty("DebugLabel", "text", getProperty("DebugLabel", "text") + "\n click ok");
                            if (a == "false") {
							 alert("ShowMessage_ShortDelayed");
                                invokeAction("", "ShowMessage_ShortDelayed")
                            }
                        }
                       // invokeAction("", "CheckMastersDelayed")

                        //setProperty("DebugLabel", "text", getProperty("DebugLabel", "text") + "\nvalidation failed");
                        //invokeAction("","Kill")

                }

		function goToVOD() {

                    alert("gotovod" + navDest)
                    invokeAction("", "NavVod", navDest)
                }

